module RefModule (
    input clk,
    input reset,
    input en,
    input load,
    input [31:0] load_val,
    output reg [31:0] q);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        q <= 32'b00000000000000000000000000000000;
    else if (load)
        q <= load_val;
    else if (en)
        q <= q + 1;
end

endmodule
